import{_ as a,c as i,o as n,a4 as r}from"./chunks/framework.Cjj1onnZ.js";const o="/images/intro/%E6%8F%92%E4%BB%B6%E7%B3%BB%E7%BB%9F%E7%9A%84%E5%85%B3%E7%B3%BB%E8%A7%86%E5%9B%BE_en.svg",f=JSON.parse('{"title":"About Extensions","description":"","frontmatter":{},"headers":[],"relativePath":"en/01-intro/01-about.md","filePath":"en/01-intro/01-about.md"}'),t={name:"en/01-intro/01-about.md"};function s(l,e,c,d,h,p){return n(),i("div",{"data-pagefind-body":!0},e[0]||(e[0]=[r('<h1 id="about-extensions" tabindex="-1">About Extensions <a class="header-anchor" href="#about-extensions" aria-label="Permalink to “About Extensions”">​</a></h1><h2 id="what-is-an-extension" tabindex="-1">What is an Extension <a class="header-anchor" href="#what-is-an-extension" aria-label="Permalink to “What is an Extension”">​</a></h2><ul><li>The extension system provides a complete framework that allows ecosystem partners and external developers to develop applications according to certain rules and run them in Agilebot robots.</li><li>The Copper/Bronze system allows running 3 types of user-defined programs: Web Mini Programs, Easy Services, and General Services.</li></ul><p>Taking Copper as an example, their relationship is as follows:</p><figure><img src="'+o+'" alt=""></figure><h2 id="extension-categories" tabindex="-1">Extension Categories <a class="header-anchor" href="#extension-categories" aria-label="Permalink to “Extension Categories”">​</a></h2><h3 id="web-mini-program-webminiprogram" tabindex="-1">Web Mini Program <code>webMiniProgram</code> <a class="header-anchor" href="#web-mini-program-webminiprogram" aria-label="Permalink to “Web Mini Program webMiniProgram”">​</a></h3><p>Web Mini Programs allow developers to write the frontend interface of extensions using web technologies (such as HTML, CSS, JavaScript) and embed them into the system&#39;s web pages for display and interaction as frontend pages.</p><h3 id="easy-service-easyservice" tabindex="-1">Easy Service <code>easyService</code> <a class="header-anchor" href="#easy-service-easyservice" aria-label="Permalink to “Easy Service easyService”">​</a></h3><p>Easy Service extensions are plugins that implement functionality by writing one or more Python methods. They allow developers to quickly implement simple backend functionality and interact with the system through HTTP requests. Easy Services typically do not involve complex frameworks or external dependencies, requiring only the writing of some methods.</p><h3 id="general-service-generalservice" tabindex="-1">General Service <code>generalService</code> <a class="header-anchor" href="#general-service-generalservice" aria-label="Permalink to “General Service generalService”">​</a></h3><p>General Service extensions can provide more powerful functionality support. They are usually more complex backend services capable of data processing, complex logical operations, or interaction with external systems.</p><h2 id="extension-file-composition" tabindex="-1">Extension File Composition <a class="header-anchor" href="#extension-file-composition" aria-label="Permalink to “Extension File Composition”">​</a></h2><h3 id="configuration-file" tabindex="-1">Configuration File <a class="header-anchor" href="#configuration-file" aria-label="Permalink to “Configuration File”">​</a></h3><p>Any type of extension must include a <code>config.json</code> file, which is the <a href="./../03-reference/01-config.html">configuration file</a>. Only extensions containing a configuration file can be installed, initialized, and run.</p><h3 id="data-files" tabindex="-1">Data Files <a class="header-anchor" href="#data-files" aria-label="Permalink to “Data Files”">​</a></h3><p>Backend extension packages generally include a data directory for storing data generated during extension runtime. For details, refer to <a href="./../02-development/03-advanced/04-data-persistence.html">Data Persistence</a>.</p>',17)]))}const g=a(t,[["render",s]]);export{f as __pageData,g as default};
